using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap the JSONPlaceholder REST API via HttpClient.
/// Uses constructor injection — the SDK resolves HttpClient and ILogger
/// from DI and does NOT expose them in the tool schema.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("List posts from the API. Optionally filter by user ID.")]
    public async Task<string> ListPosts(
        [Description("Filter posts to this user ID (omit for all posts)")] int? userId = null,
        CancellationToken cancellationToken = default)
    {
        var url = userId.HasValue
            ? $"/posts?userId={userId.Value}"
            : "/posts";

        logger.LogInformation("GET {Url}", url);
        var json = await httpClient.GetStringAsync(url, cancellationToken);

        using var doc = JsonDocument.Parse(json);
        var count = doc.RootElement.GetArrayLength();
        return $"Found {count} posts.\n{json}";
    }

    [McpServerTool, Description("Get a single post by its ID.")]
    public async Task<string> GetPost(
        [Description("The numeric ID of the post to retrieve")] int id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("GET /posts/{Id}", id);
        var response = await httpClient.GetAsync($"/posts/{id}", cancellationToken);

        if (!response.IsSuccessStatusCode)
            return $"Error: {(int)response.StatusCode} {response.ReasonPhrase}";

        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }

    [McpServerTool, Description("Create a new post with a title and body for a given user.")]
    public async Task<string> CreatePost(
        [Description("User ID of the post author")] int userId,
        [Description("Title of the new post")] string title,
        [Description("Body content of the new post")] string body,
        CancellationToken cancellationToken = default)
    {
        var payload = JsonSerializer.Serialize(new { userId, title, body });
        var content = new StringContent(payload, Encoding.UTF8, "application/json");

        logger.LogInformation("POST /posts");
        var response = await httpClient.PostAsync("/posts", content, cancellationToken);

        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return $"Status: {(int)response.StatusCode}\n{json}";
    }
}

